<script setup>
import { computed, reactive, ref } from 'vue';
import { Head, Link } from '@inertiajs/vue3';
import axios from 'axios';
const props=defineProps({attendance:Array,events:Array,corrections:Array});
const correctionItems=ref([...props.corrections]);const messages=reactive({});
const minutes=(time)=>{if(!time)return 0;const[h,m]=time.split(':').map(Number);return h*60+m};
const duration=(time)=>time?Math.max(0,minutes(time.endzeit)-minutes(time.startzeit)):0;
const present=(entry)=>entry.status?.status?.toLowerCase()==='anwesend';
const balance=(entry)=>(present(entry)?duration(entry.zeittatsaechlich):0)-duration(entry.zeitgeplant);
const formatMinutes=(value)=>{const sign=value<0?'-':value>0?'+':'';const abs=Math.abs(value);return `${sign}${String(Math.floor(abs/60)).padStart(2,'0')}:${String(abs%60).padStart(2,'0')}`};
const correctionFor=(id)=>correctionItems.value.find(item=>item.attendance_id===id);
const requestCorrection=async(entry)=>{if(!messages[entry.id]?.trim())return;const r=await axios.post(route('participant-portal.attendance.corrections.store',entry.id),{message:messages[entry.id]});correctionItems.value.unshift(r.data.correction);messages[entry.id]='';};
const totals=computed(()=>({days:props.attendance.length,balance:props.attendance.reduce((sum,item)=>sum+balance(item),0),absent:props.attendance.filter(item=>!present(item)).length}));
</script>
<template><Head title="Anwesenheit und Termine"/><main class="min-h-screen bg-sky-50 px-5 py-8"><div class="mx-auto max-w-6xl space-y-6"><header class="flex justify-between"><div><p class="text-xs font-semibold uppercase tracking-widest text-zbb">Matrix Teilnehmerportal</p><h1 class="text-2xl font-bold">Anwesenheit und Termine</h1></div><Link :href="route('participant-portal.dashboard')" class="rounded border bg-white px-4 py-2 text-sm">Dashboard</Link></header><div class="grid gap-3 sm:grid-cols-3"><div class="rounded-xl bg-white p-4 shadow"><p class="text-xs text-gray-500">Erfasste Tage</p><p class="text-2xl font-bold">{{ totals.days }}</p></div><div class="rounded-xl bg-white p-4 shadow"><p class="text-xs text-gray-500">Abwesenheiten</p><p class="text-2xl font-bold">{{ totals.absent }}</p></div><div class="rounded-xl bg-white p-4 shadow"><p class="text-xs text-gray-500">Gesamtsaldo</p><p class="text-2xl font-bold" :class="totals.balance<0?'text-red-600':'text-green-600'">{{ formatMinutes(totals.balance) }}</p></div></div><div class="grid gap-6 lg:grid-cols-[1fr_360px]"><section class="rounded-2xl border bg-white p-5 shadow"><h2 class="text-lg font-semibold">Meine Anwesenheit</h2><div class="mt-4 space-y-3"><article v-for="entry in attendance" :key="entry.id" class="rounded-xl border p-4"><div class="flex justify-between"><div><p class="font-semibold">{{ new Date(entry.tag.datum).toLocaleDateString('de-DE') }} · {{ entry.gruppe?.projekt?.name }}</p><p class="text-sm text-gray-500">{{ entry.gruppe?.bereich?.name }} · {{ entry.status?.status }}</p></div><p class="font-mono font-semibold" :class="balance(entry)<0?'text-red-600':'text-gray-700'">{{ formatMinutes(balance(entry)) }}</p></div><div v-if="correctionFor(entry.id)" class="mt-3 rounded bg-gray-50 p-3 text-xs"><strong>Korrekturanfrage: {{ correctionFor(entry.id).status }}</strong><p>{{ correctionFor(entry.id).message }}</p><p v-if="correctionFor(entry.id).resolution_note">Antwort: {{ correctionFor(entry.id).resolution_note }}</p></div><div v-else class="mt-3 flex gap-2"><input v-model="messages[entry.id]" maxlength="2000" placeholder="Was soll geprüft werden?" class="flex-1 rounded border-gray-300 text-sm"/><button class="rounded border px-3 py-2 text-xs" @click="requestCorrection(entry)">Prüfung anfragen</button></div></article><p v-if="!attendance.length" class="text-sm text-gray-500">Keine freigegebenen Anwesenheitsdaten.</p></div></section><section class="rounded-2xl border bg-white p-5 shadow"><h2 class="text-lg font-semibold">Meine Termine</h2><div class="mt-4 space-y-3"><article v-for="event in events" :key="event.id" class="rounded-xl border p-3"><p class="font-semibold">{{ event.title }}</p><p class="text-sm text-gray-500">{{ new Date(event.starts_at).toLocaleString('de-DE') }}</p><p class="text-sm text-gray-500">{{ event.location }}</p></article><p v-if="!events.length" class="text-sm text-gray-500">Keine anstehenden Projekttermine.</p></div></section></div></div></main></template>
